export function addAmiriFont(doc: any) {
    // This is a base64 encoded Amiri-Regular.ttf font.
    // It's required by jsPDF to handle Arabic text.
    const amiriFont = '-Regular.ttf';
    doc.addFileToVFS('Amiri-Bold.ttf', amiriFont);
    doc.addFont('Amiri-Regular.ttf', 'Amiri', 'normal');
}
